css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  -webkit-mask: linear-gradient(90deg,currentColor 70%,#0000 0) left/20% 100%;
  background:linear-gradient(currentColor 0 0) left -25% top 0 /20% 100% no-repeat var(--loader-secondary-color, #a5b4fc);
  animation: l7 1s infinite steps(6);
}@keyframes l7 {100% {background-position: right -25% top 0}}
